1_da_yun_luck_pillars.implementation_pseudo:
function getDaYun(natal, gender) {
  const direction = isForward(natal.year.stem, gender) ? 'forward' : 'reverse';
  const startAge = calcStartAge(natal.birthDate, direction);
  const monthIdx = jiaZi60.indexOf(natal.month.stem + natal.month.branch);
  const pillars = [];
  for (let i = 0; i < 10; i++) {
    const idx = direction === 'forward' 
      ? (monthIdx + i + 1) % 60
      : (monthIdx - i - 1 + 60) % 60;
    pillars.push({
      pillar: jiaZi60[idx],
      startAge: startAge + (i * 10),
      endAge: startAge + ((i+1) * 10) - 1
    });
  }
  return { direction, startAge, pillars };
}

2_liu_nian_annual_pillar.calculation_function:
function getLiuNian(year) {
  // Get year stem-branch using Jia Zi cycle
  // Anchor: 1900 = 庚子 (year stem 庚 idx=6, branch 子 idx=0)
  // Or use 立春 boundary check via solar term table
  const date = new Date(year, 1, 5); // Feb 5 = past 立春
  return c2(date); // Hourkey's verified function
}

3_liu_yue_monthly_pillar.calculation_function:
function getLiuYue(year, month) {
  // Month boundary follows solar terms (jie qi)
  // Use mid-month date to be safe
  const date = new Date(year, month - 1, 15);
  return Er(date);
}

4_liu_ri_daily_pillar.calculation_function:
function getLiuRi(date) {
  // Anchor: 1900-01-01 = 甲戌 day
  // Day pillar advances by 1 each day in Jia Zi cycle
  return g2(date);
}

5_liu_shi_hourly_pillar.calculation_function:
function getLiuShi(date) {
  // Hour branch determined by 2-hour blocks
  // Hour stem = (day_stem_index * 2 + hour_branch_index) % 10
  return Dr(date);
}

6_unified_transit_function.implementation:
function getAllTransits(birthDate, currentDate, gender) {
  const natal = calculateNatal(birthDate);
  const daYun = getDaYun(natal, gender);
  const liuNian = getLiuNian(currentDate.getFullYear());
  const liuYue = getLiuYue(currentDate.getFullYear(), currentDate.getMonth() + 1);
  const liuRi = getLiuRi(currentDate);
  const liuShi = getLiuShi(currentDate);

  return {
    da_yun: daYun.pillars[getCurrentPillarIndex(daYun, currentDate)],
    liu_nian: liuNian,
    liu_yue: liuYue,
    liu_ri: liuRi,
    liu_shi: liuShi,

    // Combined scoring
    natal: natal,
    transit_score: calculateTransitScore(natal, daYun, liuNian, liuYue, liuRi, liuShi),
    action_mode: determineActionMode(transit_score),
    activated_stars: detectActivatedStars(natal, [daYun, liuNian, liuYue, liuRi, liuShi]),
    activated_destructions: detect6Destructions([natal, daYun, liuNian, liuYue, liuRi, liuShi])
  };
}
